import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import supportService from '../services/supportService';

export default function CustomerService() {
    const { user } = useAuth();
    const [formData, setFormData] = useState({
        subject: '',
        message: '',
    });
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState('');
    const [error, setError] = useState('');

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
        setError('');
        setSuccess('');
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        if (!user) {
            setError('Please log in to send a concern.');
            return;
        }

        setLoading(true);
        setError('');
        setSuccess('');

        try {
            await supportService.submitConcern(formData);
            setSuccess('Your concern has been sent. We will review it soon.');
            setFormData({ subject: '', message: '' });
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to send your concern.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="customer-service-page">
            <div className="container">
                <header className="customer-service-hero">
                    <div className="customer-service-hero__content">
                        <p className="customer-service-kicker">Customer Service</p>
                        <h1>Help Center built for fast answers</h1>
                        <p>
                            Get support for orders, returns, shipping, and account questions in one place.
                            We keep it simple so customers can find what they need quickly.
                        </p>

                        <div className="customer-service-hero__actions">
                            <Link to="/dashboard/orders" className="btn btn-primary">View My Orders</Link>
                            <Link to="/dashboard/profile" className="btn btn-outline-primary">Manage Account</Link>
                        </div>
                    </div>

                    <div className="customer-service-hero__panel">
                        <div className="support-tile">
                            <span className="support-tile__label">Response Time</span>
                            <strong>Within 24 hours</strong>
                        </div>
                        <div className="support-tile">
                            <span className="support-tile__label">Shipping Window</span>
                            <strong>3 - 5 business days</strong>
                        </div>
                        <div className="support-tile">
                            <span className="support-tile__label">Support Email</span>
                            <strong>support@carvex.ph</strong>
                        </div>
                    </div>
                </header>

                <section className="customer-service-quick-links">
                    <Link to="#faq" className="service-pill">FAQ</Link>
                    <Link to="#returns" className="service-pill">Returns</Link>
                    <Link to="#shipping" className="service-pill">Shipping</Link>
                    <Link to="#contact" className="service-pill">Contact Us</Link>
                </section>

                <div className="customer-service-grid">
                    <section id="faq" className="customer-service-card customer-service-card--featured">
                        <div className="customer-service-card__header">
                            <h2>FAQ</h2>
                            <p>Common questions from customers.</p>
                        </div>
                        <div className="customer-service-list">
                            <article>
                                <h3>How do I track my order?</h3>
                                <p>Open your Orders page after logging in to view status and updates.</p>
                            </article>
                            <article>
                                <h3>Can I cancel an order?</h3>
                                <p>Eligible orders can be cancelled from your account before processing finishes.</p>
                            </article>
                            <article>
                                <h3>Do you sell genuine parts?</h3>
                                <p>We focus on quality parts sourced from trusted suppliers and brands.</p>
                            </article>
                        </div>
                    </section>

                    <section id="contact" className="customer-service-card customer-service-card--contact">
                        <div className="customer-service-card__header">
                            <h2>Contact Us</h2>
                            <p>Reach the CarVex support team directly.</p>
                        </div>
                        <div className="contact-stack">
                            <div className="contact-row">
                                <span className="contact-row__label">Email</span>
                                <strong>support@carvex.ph</strong>
                            </div>
                            <div className="contact-row">
                                <span className="contact-row__label">Phone</span>
                                <strong>+63 917 123 4567</strong>
                            </div>
                            <div className="contact-row">
                                <span className="contact-row__label">Location</span>
                                <strong>Agusan del Norte, Butuan City</strong>
                            </div>
                        </div>
                        <a href="#support-form" className="btn btn-primary btn-block">Send a Concern</a>
                    </section>

                    <section id="returns" className="customer-service-card">
                        <div className="customer-service-card__header">
                            <h2>Returns</h2>
                            <p>Simple and clear return guidance.</p>
                        </div>
                        <ul>
                            <li>Returns are accepted within 7 days after delivery.</li>
                            <li>Items must be unused and returned in original packaging.</li>
                            <li>Contact support first so we can assist the return process.</li>
                        </ul>
                    </section>

                    <section id="shipping" className="customer-service-card">
                        <div className="customer-service-card__header">
                            <h2>Shipping</h2>
                            <p>What to expect after checkout.</p>
                        </div>
                        <ul>
                            <li>Standard delivery usually arrives in 3 to 5 business days.</li>
                            <li>Delivery time may vary by destination and courier schedule.</li>
                            <li>Customers receive updates once an order is confirmed and dispatched.</li>
                        </ul>
                    </section>

                    <section id="support-form" className="customer-service-card customer-service-card--form">
                        <div className="customer-service-card__header">
                            <h2>Send a Concern</h2>
                            <p>Message us directly from your customer account.</p>
                        </div>

                        {success && <div className="alert alert-success">{success}</div>}
                        {error && <div className="alert alert-danger">{error}</div>}

                        {user ? (
                            <form className="customer-service-form" onSubmit={handleSubmit}>
                                <div className="form-group">
                                    <label htmlFor="name">Name</label>
                                    <input id="name" type="text" value={user?.name || ''} disabled />
                                </div>

                                <div className="form-group">
                                    <label htmlFor="email">Email</label>
                                    <input id="email" type="email" value={user?.email || ''} disabled />
                                </div>

                                <div className="form-group">
                                    <label htmlFor="subject">Subject</label>
                                    <input
                                        id="subject"
                                        name="subject"
                                        type="text"
                                        value={formData.subject}
                                        onChange={handleChange}
                                        placeholder="What is this about?"
                                        required
                                        disabled={loading}
                                    />
                                </div>

                                <div className="form-group">
                                    <label htmlFor="message">Concern</label>
                                    <textarea
                                        id="message"
                                        name="message"
                                        rows="5"
                                        value={formData.message}
                                        onChange={handleChange}
                                        placeholder="Describe your concern in detail..."
                                        required
                                        disabled={loading}
                                    />
                                </div>

                                <button type="submit" className="btn btn-primary btn-block" disabled={loading}>
                                    Submit Concern
                                </button>
                            </form>
                        ) : (
                            <div className="customer-service-login-prompt">
                                <p>You need to log in before sending a concern.</p>
                                <Link to="/login" className="btn btn-primary btn-block">Log In</Link>
                            </div>
                        )}
                    </section>
                </div>
            </div>
        </div>
    );
}